function series() {
  var out = []
  var v = 100
  for (var i = 0; i < 60; i++) {
    v += 2 + Math.sin(i / 5) * 3
    out.push([i, Math.round(v)])
  }
  return out
}

var options = {
  series: [{ name: 'Price', data: series() }],
  chart: {
    id: 'price',
    type: 'area',
    height: 380,
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { enabled: false },
    measure: { enabled: true, pinOnRelease: true },
    toolbar: { show: true, autoSelected: 'measure' },
    zoom: { enabled: true, type: 'x' },
  },
  stroke: { width: 2, curve: 'straight' },
  dataLabels: { enabled: false },
  title: { text: 'Price (measure any move)', align: 'left' },
  xaxis: { type: 'numeric', title: { text: 'Session' } },
  yaxis: { title: { text: 'Price' }, decimalsInFloat: 0 },
}

var chart = new ApexCharts(document.querySelector('#chart'), options)
chart.render()

// The ruler tool is pre-selected via toolbar.autoSelected: 'measure', so the
// plot is already armed on load -- just drag. The toolbar icon toggles it (and
// the 'm' key still works); no custom wiring needed here.
var readout = document.getElementById('mz-readout')

document.getElementById('mz-clear').addEventListener('click', function () {
  chart.clearMeasures()
})

chart.addEventListener('measured', function (c, o) {
  readout.textContent =
    'dx=' +
    Number(o.dx).toFixed(2) +
    '  dy=' +
    Number(o.dy).toFixed(2) +
    '  (' +
    (o.percentChange >= 0 ? '+' : '') +
    Number(o.percentChange).toFixed(1) +
    '%)'
})

.mz-wrap {
  max-width: 820px;
  margin: 12px auto;
  font-family: Helvetica, Arial, sans-serif;
}
.mz-bar {
  display: flex;
  gap: 10px;
  align-items: center;
  flex-wrap: wrap;
  margin: 4px 6px 10px;
}
.mz-bar button {
  padding: 6px 13px;
  cursor: pointer;
  border: 1px solid #0ea5e9;
  color: #0369a1;
  background: #fff;
  border-radius: 6px;
  font-size: 13px;
  font-weight: 600;
}
.mz-bar button.active {
  background: #0ea5e9;
  color: #fff;
}
.mz-bar .readout {
  font-family: monospace;
  font-size: 13px;
  color: #445;
}
.mz-note {
  background: #f0f9ff;
  border-left: 3px solid #0ea5e9;
  padding: 11px 15px;
  font-size: 13px;
  color: #234;
  border-radius: 2px;
  line-height: 1.6;
  margin: 12px 6px;
}
.mz-note code {
  background: #dceafb;
  padding: 1px 5px;
  border-radius: 3px;
}
